/// <summary>
/// The <c>ETGPurchRegisterReportDP</c> class is the report of data provider class for Purchase register report
/// </summary>
[
    SRSReportQueryAttribute(queryStr(ETGPurchRegisterReportQuery)),
    SRSReportParameterAttribute(classStr(ETGPurchRegisterReportContract))
]
class ETGPurchRegisterReportDP extends SrsReportDataProviderPreProcessTempDB
{
    ETGPurchRegisterReportTmp       purchRegisterReportTmp;
    ETGSRSReportMultiParametersTmp  ssrsReportMultiParametersTmp;
    CreatedTransactionId            currentTransactionId, currentTransactionIdGRN, currentTransactionIdChrg;
    ETGPurchRegisterReportContract  contract;
    FromDate                        fromDate;
    ToDate                          toDate;
    DimensionSetName                financialDimSet;
    NoYes                           isDetailReport;
    EcoResConfigurationFlag         viewConfigId;
    EcoResSizeFlag                  viewInventSizeId;
    EcoResColorFlag                 viewInventColorId;
    EcoResStyleFlag                 viewInventStyleId;
    InventSiteIdFlag                viewInventSiteId;
    InventLocationIdFlag            viewInventLocationId;
    WHSLicensePlateFlag             viewLicensePlate;
    InventLocationIdFlag            viewWMSLocationId;
    WHSInventStatusFlag             viewInventStatus;
    InventBatchIdFlag               viewInventBatchId;
    InventSerialIdFlag              viewInventSerialId;
    InventOwnerIdFlag               viewInventOwnerId;
    utcDateTime                     utcFromDate, utcToDate;
    PurchId                         currentPurchId;
    RefRecId                        currentPurchLine;

    PurchTable                      purchTable;
    PurchLine                       purchLine;
    InventDim                       inventDim;

}

Method.Source:
[SRSReportDataSetAttribute(tablestr(ETGPurchRegisterReportTmp))]
public ETGPurchRegisterReportTmp getETGPurchRegisterReportTmp()
{
    select purchRegisterReportTmp;
    return purchRegisterReportTmp;
}

public void processReport()
{
    this.initContract();
    this.insertData();
    this.updateData();
    this.insertFinancialDimensions();
    this.insertQualitySpecifications();
    this.insertChargeCodes();
}

/// <summary>
///    Parses the report parameters and fills the <c>ETGPurchRegisterReportTmp</c> and <c>ETGPurchRegisterReportTmp</c>
///    tables with data.
/// </summary>
public void initContract()
{
    contract                = this.parmDataContract() as ETGPurchRegisterReportContract;
    fromDate                = contract.parmFromDate();
    toDate                  = contract.parmToDate();
    financialDimSet         = contract.parmFinancialDimSet();
    isDetailReport          = contract.parmIsDetailReport();
    viewConfigId            = contract.parmViewConfigId();
    viewInventSizeId        = contract.parmViewInventSizeId();
    viewInventColorId       = contract.parmViewInventColorId();
    viewInventStyleId       = contract.parmViewInventStyleId();
    viewInventSiteId        = contract.parmViewInventSiteId();
    viewInventLocationId    = contract.parmViewInventLocationId();
    viewLicensePlate        = contract.parmViewLicensePlateId();
    viewWMSLocationId       = contract.parmViewWMSLocationId();
    viewInventStatus        = contract.parmViewInventStatus();
    viewInventBatchId       = contract.parmViewInventBatchId();
    viewInventSerialId      = contract.parmViewInventSerialId();
    viewInventOwnerId       = contract.parmViewInventOwnerId_RU();
}

/// <summary>
///    inserting data using parm query.
/// </summary>
public void insertData()
{
    QueryRun                        queryRun;
    FiscalCalendarYear              fiscalCalendarYear;
    VendTable                       vendAccountTable;
    VendTrans                       vendTrans;
    PurchAgreementHeader            purchAgreementHeader;
    AgreementHeader                 agreementHeader;
    AgreementLine                   agreementLine;
    AgreementLineQuantityCommitment aLineCommitment;
    AgreementLineVolumeCommitment   agreementLineVolumeCommitment;
    SalesAgreementHeader            salesAgreementHeader;
    AgreementReference              agreementReference;
    VendPackingSlipJour             vendPackingSlipJour;
    VendPackingSlipTrans            vendPackingSlipTrans;
    VendInvoiceJour                 vendInvoiceJour;
    VendInvoiceTrans                vendInvoiceTrans;
    MarkupTrans                     markupTrans;
    Amount                          lineCharges,amount;
    VendInvoiceInfoTable            vendInvoiceInfoTable;
    TaxTrans                        taxTrans;
    real                            taxAmount, taxValue, invoiceAmount;
    //AgreementLineQuantityCommitment agreementLineQuantityCommitment;
    //AgreementLineVolumeCommitment   agreementLineVolumeCommitment;
    ETG_PurchTableTrade             purchTableTrade;
    ETG_OrderType                   orderType;
    VendBankAccount                 vendBankAccount;
    PurchLine                       purchLineTotal;
    PurchTotalsSummary              purchTotalsSummary;
    //InventParameters                inventParameters = InventParameters::find();
    Query                           query = this.parmQuery();
    Ledger                          ledger = Ledger::find(Ledger::current());
    PurchUnit                       purchunit;
    UnitOfMeasureConverter_Product  unitConverter   = UnitOfMeasureConverter_Product::construct();
    UnitOfMeasure                   fromunit,tounit;
    InventTransOrigin               inventTransOrigin;
    InventTrans                     inventTrans;
    ETG_PurchaseAgreementHeader     eTG_PurchaseAgreementHeader;
    ETG_AgreementType               AgreementType;



    utcFromDate = DateTimeUtil::newDateTime(fromDate, 0);
    utcToDate   = DateTimeUtil::newDateTime(toDate, 86400);
    query.dataSourceTable(tablenum(PurchTable)).addRange(fieldnum(PurchTable, CreatedDateTime)).value(queryRange(utcFromDate, utcToDate));

    queryRun = new QueryRun(query);
    while (queryRun.next())
    {
        purchTable              = queryRun.get(tableNum(PurchTable));
        purchLine               = queryRun.get(tableNum(PurchLine));
        inventDim               = queryRun.get(tableNum(InventDim));
        vendPackingSlipJour     = queryRun.get(tableNum(VendPackingSlipJour));
        vendPackingSlipTrans    = queryRun.get(tableNum(VendPackingSlipTrans));
       // vendInvoiceJour         = queryRun.get(tableNum(VendInvoiceJour));
       // vendInvoiceTrans        = queryRun.get(tableNum(VendInvoiceTrans));


        purchRegisterReportTmp.clear();

        currentPurchId      = purchLine.PurchId;
        currentPurchLine    = purchLine.RecId;
        if (currentPurchId != purchLine.PurchId || currentPurchLine != purchLine.RecId)
        {
            purchRegisterReportTmp.IsFirstLineInOrder   = NoYes::Yes;
        }
        else
        {
            purchRegisterReportTmp.IsFirstLineInOrder   = NoYes::No;
        }

        purchRegisterReportTmp.PurchTable           = purchTable.RecId;
        purchRegisterReportTmp.PurchLine            = purchLine.RecId;
        purchRegisterReportTmp.InventDim            = inventDim.RecId;
        purchRegisterReportTmp.InventTransId        = purchLine.InventTransId;
        purchRegisterReportTmp.PurchId              = purchTable.PurchId;
        purchRegisterReportTmp.IsActualOrderLine    = NoYes::Yes;
        purchRegisterReportTmp.CreatedDate          = DateTimeUtil::date(purchTable.CreatedDateTime);
        purchRegisterReportTmp.GLAccoutingCurrencyCode  = ledger.AccountingCurrency;
        purchRegisterReportTmp.GLReportingCurrencyCode  = ledger.ReportingCurrency;

        if (purchRegisterReportTmp.IsFirstLineInOrder && isDetailReport && purchLine.DefaultDimension)
        {
            purchRegisterReportTmp.DefaultDimension = purchLine.DefaultDimension;
        }
        else if (purchTable.DefaultDimension)
        {
            purchRegisterReportTmp.DefaultDimension = purchTable.DefaultDimension;
        }
        purchRegisterReportTmp.DlvTermCode          = purchTable.DlvTerm;
        purchRegisterReportTmp.DlvTermDesc          = DlvTerm::find(purchTable.DlvTerm).Txt;
        purchRegisterReportTmp.PaymTermId           = purchTable.Payment;
        purchRegisterReportTmp.PaymTermDesc         = PaymTerm::find(purchTable.Payment).Description;
        purchRegisterReportTmp.CurrencyCode         = purchTable.CurrencyCode;

        purchAgreementHeader                        = PurchAgreementHeader::find(purchTable.MatchingAgreement);
        agreementHeader                             = AgreementHeader::find(purchTable.MatchingAgreement);
        purchRegisterReportTmp.PurchConractNumber   = purchAgreementHeader.PurchNumberSequence;
        purchRegisterReportTmp.PurchContractDate    = agreementHeader.DefaultAgreementLineEffectiveDate;

        select firstonly purchTableTrade
            where purchTableTrade.PurchId == purchTable.PurchId;
        purchRegisterReportTmp.SellerBank           = purchTableTrade.SellerBank != "" ? purchTableTrade.SellerBank : purchTableTrade.SellerSecondaryBank;
        select firstonly AccountNum from vendBankAccount
            where vendBankAccount.AccountID == purchTableTrade.SellerBank;
        purchRegisterReportTmp.BankAccountNum       = vendBankAccount.AccountNum;
        //purchRegisterReportTmp.PaymTermDesc         = purchTableTrade.TermsOfDelDescription;

        select firstonly purchAgreementHeader
            where purchAgreementHeader.RecId ==  purchTable.MatchingAgreement;

        select eTG_PurchaseAgreementHeader
            where eTG_PurchaseAgreementHeader.PurchAgreementId == PurchAgreementHeader.PurchNumberSequence;

        select firstonly AgreementType
            where AgreementType.AgreementType == eTG_PurchaseAgreementHeader.AgreementType;
        purchRegisterReportTmp.AgreementType    =   AgreementType.AgreementType;
        purchRegisterReportTmp.Description      =   AgreementType.Description;

        select orderType
            where orderType.OrderType == purchTableTrade.OrderType;
        purchRegisterReportTmp.OrderTypeDescription = orderType.Description;
        purchRegisterReportTmp.OrderType            = orderType.OrderType;

        select firstonly CommitedQuantity, ProductUnitOfMeasure, PricePerUnit, RecId from aLineCommitment order by RecId
            join agreementLine
            where agreementLine.RecId == aLineCommitment.RecId
            && agreementLine.Agreement == agreementHeader.RecId;

        select firstonly CommitedAmount from agreementLineVolumeCommitment
            where agreementLineVolumeCommitment.RecId == aLineCommitment.RecId;

        purchRegisterReportTmp.PurchContractQty     = aLineCommitment.CommitedQuantity;
        purchRegisterReportTmp.PurchContractValue   = aLineCommitment.CommitedQuantity * aLineCommitment.PricePerUnit;
        purchRegisterReportTmp.PurchContractPrice   = aLineCommitment.PricePerUnit;

        select firstonly salesAgreementHeader
        join agreementReference
            where salesAgreementHeader.RecId == agreementReference.DerivedAgreement
            && agreementReference.SourceAgreement == purchTable.MatchingAgreement;

        purchRegisterReportTmp.SalesContractNumber  = salesAgreementHeader.SalesNumberSequence;

        vendAccountTable                            = purchTable.vendTable_OrderAccount();
        purchRegisterReportTmp.VendAccount          = vendAccountTable.AccountNum;
        purchRegisterReportTmp.VendName             = vendAccountTable.name();
        purchRegisterReportTmp.VendGroup            = vendAccountTable.VendGroup;
        purchRegisterReportTmp.VendGroupName        = VendGroup::find(vendAccountTable.VendGroup).Name;

        select firstonly Name from fiscalCalendarYear
            where fiscalCalendarYear.StartDate <= purchRegisterReportTmp.CreatedDate
            && fiscalCalendarYear.EndDate >= purchRegisterReportTmp.CreatedDate;
        purchRegisterReportTmp.AccountingPeriod     = fiscalCalendarYear.Name;

        //****
        purchRegisterReportTmp.DeliveryOrderNum     = vendPackingSlipJour.PackingSlipId;
        purchRegisterReportTmp.DeliveryOrderDate    = vendPackingSlipJour.DeliveryDate;
        purchRegisterReportTmp.DeliveryQty          = vendPackingSlipTrans.Qty;//Venkat
        //purchRegisterReportTmp.DeliveryLineAmt      = vendPackingSlipTrans.ValueMST;//Venkat
        purchRegisterReportTmp.VendPackingSlipTrans = vendPackingSlipTrans.RecId;
        purchRegisterReportTmp.InventTransIdGRN     = vendPackingSlipTrans.InventTransId;

        purchRegisterReportTmp.DeliveryQty          = vendPackingSlipTrans.Qty;
        purchRegisterReportTmp.DeliveryLineAmt      = vendPackingSlipTrans.ValueMST;

        select firstonly inventTransOrigin
            where inventTransOrigin.ReferenceId == purchline.PurchId;
        select firstonly inventTrans
            where inventTrans.InventTransOrigin == inventTransOrigin.RecId
            && inventTrans.PackingSlipId        == vendPackingSlipJour.PackingSlipId;
        select firstonly vendInvoiceTrans
            where vendInvoiceTrans.InventTransId == inventTransorigin.InventTransId
            &&  vendInvoiceTrans.Qty             == inventTrans.Qty;
        select firstonly vendInvoiceJour
            where vendInvoiceJour.PurchId        == purchLine.PurchID
            && vendInvoiceJour.ledgerVoucher     == inventTrans.Voucher;


        purchRegisterReportTmp.InvoiceId            = inventTrans.InvoiceId;
        purchRegisterReportTmp.InvoiceDate          = vendInvoiceJour.InvoiceDate;
        purchRegisterReportTmp.InvoiceQty           = vendInvoiceTrans.Qty;
        purchRegisterReportTmp.InvoiceRate          = vendInvoiceTrans.PurchPrice;
        purchRegisterReportTmp.InvoiceValue         = vendInvoiceJour.InvoiceAmount;//Venkat
        purchRegisterReportTmp.BLNumber             = vendInvoiceJour.ETG_BLnumber;
        purchRegisterReportTmp.BLDate               = vendInvoiceJour.ETG_BLDate;

        select firstonly vendTrans
        where vendTrans.TransDate == vendInvoiceJour.InvoiceDate
        && vendTrans.AccountNum == vendInvoiceJour.InvoiceAccount
        && vendTrans.Voucher == vendInvoiceJour.LedgerVoucher;

        purchRegisterReportTmp.ExchRate         = vendTrans.ExchRate != 0 ? vendTrans.ExchRate/100 : 0;
        purchRegisterReportTmp.AmountCur        = vendTrans.AmountCur;
        purchRegisterReportTmp.ReportingCurrencyAmount  = vendTrans.ReportingCurrencyAmount;
        purchRegisterReportTmp.AmountInUSD      = purchRegisterReportTmp.ReportingCurrencyAmount;
        purchRegisterReportTmp.InvCurrencyCode  = vendTrans.CurrencyCode;
        purchRegisterReportTmp.AmountMST  = vendTrans.AmountMST;

        select firstonly SourceRegulateAmountCur, TaxValue, TaxCode from taxTrans
            where taxTrans.SourceRecId == vendInvoiceTrans.RecId
            && taxTrans.SourceTableId == tableNum(VendInvoiceTrans);
        purchRegisterReportTmp.TaxAmount            = taxTrans.SourceRegulateAmountCur;
        purchRegisterReportTmp.TaxValue             = taxTrans.TaxValue;
        purchRegisterReportTmp.TaxCode              = taxTrans.TaxCode;

       // if(vendInvoiceJour)
       // {
            select firstonly Num, DocumentDate from vendInvoiceInfoTable
                where vendInvoiceInfoTable.PurchId == purchTable.PurchId
            && vendInvoiceInfoTable.Num != ''; 
            purchRegisterReportTmp.ProformaInvNum       = vendInvoiceInfoTable.Num;
            purchRegisterReportTmp.ProformaInvDate      = vendInvoiceInfoTable.DocumentDate;
      //  }


        purchRegisterReportTmp.ItemName             = purchLine.itemName();
        purchRegisterReportTmp.ItemId               = purchLine.ItemId;
        purchRegisterReportTmp.PurchUnit            = purchLine.PurchUnit;
        purchRegisterReportTmp.SKU                  = InventTableModule::find(purchLine.ItemId, ModuleInventPurchSales::Invent).UnitId;
        purchRegisterReportTmp.PurchPrice           = purchLine.PurchPrice;
        purchRegisterReportTmp.PurchQty             = purchLine.PurchQty;
        purchRegisterReportTmp.PurchQtyInTon        = this.getNormalConversion(purchLine.ItemId, purchLine.PurchQty, purchLine.PurchUnit, "MT");
        if (purchRegisterReportTmp.PurchQtyInTon == 0 && purchLine.ItemId && purchLine.PurchQty && purchLine.PurchUnit)
        {
            purchRegisterReportTmp.PurchQtyInTon    = this.getStandardConversion(purchLine.ItemId, purchLine.PurchQty, purchLine.PurchUnit, "MT");
        }
        purchRegisterReportTmp.PurchQtyInTon        = purchRegisterReportTmp.PurchQtyInTon != 0 ? purchRegisterReportTmp.PurchQtyInTon : purchRegisterReportTmp.PurchQty;

        // changed by dileep on 27-05-2021
        purchunit                                   = purchLine.PurchUnit;
        tounit =  UnitOfMeasure::findBySymbol('MT');
        fromunit = UnitOfMeasure::findBySymbol(purchLine.PurchUnit);
        unitConverter.parmProduct(purchLine.inventTable().Product);
        unitConverter.parmFromUnitOfMeasure(fromunit.RecId);
        unitConverter.parmToUnitOfMeasure(tounit.RecId);
        unitConverter.parmRoundAbsoluteValue(NoYes::No);
        unitConverter.parmApplyRounding(NoYes::No);

        purchRegisterReportTmp.PricePerMT           = unitConverter.convertValue(purchLine.LineAmount / purchLine.PurchQty);
        // changed by dileep on 27-05-2021

        purchRegisterReportTmp.LineAmount           = purchLine.LineAmount;

        select sum(LineAmount) from purchLineTotal
            where purchLineTotal.PurchId == purchTable.PurchId;

        purchRegisterReportTmp.LineAmount           = purchLineTotal.LineAmount;

        select firstonly TotalAmount from purchTotalsSummary
            where purchTotalsSummary.PurchId == purchTable.PurchId;

        purchRegisterReportTmp.TotalLineAmount      = purchTotalsSummary ? (purchLine.LineAmount + purchTotalsSummary.MiscCharges + purchTotalsSummary.SalesTax) : (purchLine.LineAmount);

        purchRegisterReportTmp.InventColorId        = inventDim.InventColorId;
        purchRegisterReportTmp.inventBatchId        = inventDim.inventBatchId;
        if (!purchRegisterReportTmp.inventBatchId)
        {
            purchRegisterReportTmp.inventBatchId    = InventTrans::findTransId(vendPackingSlipTrans.InventTransId).inventDim().wMSLocationId;
        }
        purchRegisterReportTmp.InventStyleId        = inventDim.InventStyleId;
        purchRegisterReportTmp.configId             = inventDim.configId;
        purchRegisterReportTmp.InventSizeId         = inventDim.InventSizeId;
        purchRegisterReportTmp.InventSiteId         = inventDim.InventSiteId;
        purchRegisterReportTmp.InventSiteName       = InventSite::find(inventDim.InventSiteId).Name;
        purchRegisterReportTmp.InventLocationId     = inventDim.InventLocationId;
        purchRegisterReportTmp.InventLocationName   = InventLocation::find(inventDim.InventLocationId).Name;
        purchRegisterReportTmp.wMSLocationId        = inventDim.wMSLocationId;
        if (!purchRegisterReportTmp.wMSLocationId)
        {
            purchRegisterReportTmp.wMSLocationId    = InventTrans::findTransId(vendPackingSlipTrans.InventTransId).inventDim().wMSLocationId;
        }
        purchRegisterReportTmp.LicensePlateId       = inventDim.LicensePlateId;
        purchRegisterReportTmp.InventStatusId       = inventDim.InventStatusId;
        purchRegisterReportTmp.inventSerialId       = inventDim.inventSerialId;
        purchRegisterReportTmp.InventOwnerId_RU     = inventDim.InventOwnerId_RU;
        // 17/02/2021 start
        purchRegisterReportTmp.CompanyLogo     = FormLetter::companyLogo();
        // 17/02/2021 end

        lineCharges = 0;
        //Looping the table to get all value in absolute
        while select CalculatedAmount from markupTrans
            where markupTrans.TransTableId == tableNum(VendInvoiceTrans)
            && markupTrans.TransRecId == vendInvoiceTrans.RecId
        {
            lineCharges = lineCharges + abs(markupTrans.CalculatedAmount);
        }
        purchRegisterReportTmp.MarkupValue          = lineCharges;

        purchRegisterReportTmp.insert();
    }
}

public Description getFinDimValue(DimensionDefault _defaultDimension, Name     _dimensionName)
{
    DimensionAttributeValueSetStorage   dimStorage;
    DimensionAttribute                  dimAttribute;
    DimensionValue                      displayValue = "";
    Description                         dimDescription = "";
    int                                 i;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);
    for (i= 1 ; i<= dimStorage.elements() ; i++)
    {
        dimAttribute    = DimensionAttribute::find(dimStorage.getAttributeByIndex(i));

        if(dimAttribute.Name == _dimensionName)
        {
            displayValue    = dimStorage.getDisplayValueByIndex(i);
            dimDescription  = DimensionFinancialTag::findByFinancialTagCategoryAndValue(dimAttribute.financialTagCategory(), displayValue).Description;
            if (dimDescription == "")
            {
                dimDescription  = this.getFinDimValueDescription(dimAttribute.ViewName, displayValue);
            }
        }
    }

    return  dimDescription;
}

public Description getFinDimValueDescription(TableNameShort     _ViewName, DimensionValue   _displayValue)
{
    DimAttributeInventTable         inventTable;
    DimAttributeHcmWorker           worker;
    DimAttributeCustTable           custTable;
    DimAttributeVendTable           dimVendTable;
    DimAttributeAssetTable          assetTable;
    DimAttributeOMBusinessUnit      businessUnit;
    DimAttributeOMCostCenter        costCenter;
    DimAttributeOMDepartment        department;
    Description                     dimDescription = "";

    switch (_ViewName)
    {
        case  "DimAttributeInventTable":
            select Name from inventTable
                where inventTable.value == _displayValue;
            dimDescription = inventTable.Name;
            break;
        case  "DimAttributeHcmWorker":
            select Name from worker
                where worker.value == _displayValue;
            dimDescription = worker.Name;
            break;
        case  "DimAttributeCustTable":
            select Name from custTable
                where custTable.value == _displayValue;
            dimDescription = custTable.Name;
            break;
        case  "DimAttributeVendTable":
            select Name from dimVendTable
                where dimVendTable.value == _displayValue;
            dimDescription = dimVendTable.Name;
            break;
        case  "DimAttributeAssetTable":
            select Name from assetTable
                where assetTable.value == _displayValue;
            dimDescription = assetTable.Name;
            break;
        case  "DimAttributeOMBusinessUnit":
            select Name from businessUnit
                where businessUnit.value == _displayValue;
            dimDescription = businessUnit.Name;
            break;
        case  "DimAttributeOMCostCenter":
            select Name from costCenter
                where costCenter.value == _displayValue;
            dimDescription = costCenter.Name;
            break;
        case  "DimAttributeOMDepartment":
            select Name from department
                where department.value == _displayValue;
            dimDescription = department.Name;
            break;
    }

    return      dimDescription;
}

private PurchOrderedQty getNormalConversion(ItemId  _ItemId, Qty    _Qty, UnitOfMeasureSymbol _FromUOM, UnitOfMeasureSymbol _ToUOM)
{
    InventTable             inventTable;
    UnitOfMeasureConversion unitOfMeasureConversion;
    UnitOfMeasure           fromUnitOfMeasure, toUnitOfMeasure;
    PurchOrderedQty         returnValue;

    select firstonly Factor from unitOfMeasureConversion
    exists join InventTable
        where inventTable.ItemId == _ItemId
        && unitOfMeasureConversion.Product == InventTable.Product
    exists join fromUnitOfMeasure // FromUnit
    where fromUnitOfMeasure.RecId == unitOfMeasureConversion.FromUnitOfMeasure
        && fromUnitOfMeasure.Symbol == _FromUOM
    exists join toUnitOfMeasure //ToUnit
    where toUnitOfMeasure.RecId == unitOfMeasureConversion.TOUNITOFMEASURE
        && toUnitOfMeasure.Symbol == _ToUOM;

    returnValue = unitOfMeasureConversion.Factor != 0 ? roundup(_Qty/unitOfMeasureConversion.Factor, 1) : 0;

    return returnValue;
}

private PurchOrderedQty getStandardConversion(ItemId  _ItemId, Qty    _Qty, UnitOfMeasureSymbol _FromUOM, UnitOfMeasureSymbol _ToUOM)
{
    PurchOrderedQty                 returnValue = 0;
    InventTable                     inventTable;
    UnitOfMeasureConversion         unitOfMeasureConversion;
    UnitOfMeasure                   fromUnitOfMeasure, toUnitOfMeasure;
    UnitOfMeasureConverter_Product  unitConverter  = UnitOfMeasureConverter_Product::construct();

    select firstonly unitOfMeasureConversion
    exists join inventTable
        where inventTable.ItemId == _ItemId
        && unitOfMeasureConversion.Product == inventTable.Product
    exists join fromUnitOfMeasure // FromUnit
    where fromUnitOfMeasure.RecId == unitOfMeasureConversion.FromUnitOfMeasure
        && fromUnitOfMeasure.Symbol == _FromUOM
    exists join toUnitOfMeasure //ToUnit
    where toUnitOfMeasure.RecId == unitOfMeasureConversion.TOUNITOFMEASURE
        && toUnitOfMeasure.Symbol == _ToUOM;

    unitConverter.parmProduct(InventTable::find(_ItemId,true).Product);
    unitConverter.parmFromUnitOfMeasure(UnitOfMeasure::unitOfMeasureIdBySymbol(_FromUOM));
    unitConverter.parmToUnitOfMeasure(UnitOfMeasure::unitOfMeasureIdBySymbol(_ToUOM));
    unitConverter.parmRoundAbsoluteValue(NoYes::Yes);
    unitConverter.parmApplyRounding(NoYes::Yes);

    if (unitOfMeasureConversion)
    {
        returnValue = unitConverter.convertValue(_Qty);
    }

    return returnValue;
}

public boolean isDimensionIncludedInSet(Name        _setName, Name     _dimensionName)
{
    FinancialDimensionSetEntity     financialDimensionSetEntity;

    select firstonly financialDimensionSetEntity
        where financialDimensionSetEntity.Name == _setName
        && (financialDimensionSetEntity.SegmentName01 == _dimensionName ||
        financialDimensionSetEntity.SegmentName02 == _dimensionName ||
        financialDimensionSetEntity.SegmentName03 == _dimensionName ||
        financialDimensionSetEntity.SegmentName04 == _dimensionName ||
        financialDimensionSetEntity.SegmentName05 == _dimensionName ||
        financialDimensionSetEntity.SegmentName06 == _dimensionName ||
        financialDimensionSetEntity.SegmentName07 == _dimensionName ||
        financialDimensionSetEntity.SegmentName08 == _dimensionName ||
        financialDimensionSetEntity.SegmentName09 == _dimensionName ||
        financialDimensionSetEntity.SegmentName10 == _dimensionName ||
        financialDimensionSetEntity.SegmentName11 == _dimensionName
        );

    return financialDimensionSetEntity.RecId;
}

/// <summary>
///    updating data useing for inserted columns
/// </summary>
public void updateData()
{
    PurchId         curPurchId;
    RefRecId        curPurchLine;
    PackingSlipId   curPackingSlipId;
    InvoiceId       curInvoiceId;

    //Making zeror for repeated Lines. (While doing SUM value will vary since they are repeating)
    if (!isDetailReport)
    {
        ttsbegin;
        while select forupdate purchRegisterReportTmp
            order by InvoiceId
            where purchRegisterReportTmp.InvoiceId
        {
            if (curInvoiceId != purchRegisterReportTmp.InvoiceId)
            {
                curInvoiceId        = purchRegisterReportTmp.InvoiceId;
            }
            else
            {
                purchRegisterReportTmp.InvoiceQty       = 0;
                purchRegisterReportTmp.InvoiceRate      = 0;
                purchRegisterReportTmp.InvoiceValue     = 0;
                purchRegisterReportTmp.AmountCur        = 0;
                purchRegisterReportTmp.ReportingCurrencyAmount  = 0;
                purchRegisterReportTmp.AmountMST        = 0;
                purchRegisterReportTmp.TaxAmount        = 0;
                purchRegisterReportTmp.update();
            }
        }

        while select forupdate purchRegisterReportTmp
            order by PurchId
            where purchRegisterReportTmp.PurchId
        {

            if (curPurchId != purchRegisterReportTmp.PurchId)
            {
                curPurchId        = purchRegisterReportTmp.PurchId;
            }
            else
            {
                purchRegisterReportTmp.TotalLineAmount  = 0;
                purchRegisterReportTmp.update();
            }
        }

        while select forupdate purchRegisterReportTmp
            order by PurchLine
            where purchRegisterReportTmp.PurchLine
        {
            if (curPurchLine != purchRegisterReportTmp.PurchLine)
            {
                curPurchLine        = purchRegisterReportTmp.PurchLine;
            }
            else
            {
                purchRegisterReportTmp.PurchQty         = 0;
                purchRegisterReportTmp.PurchQtyInTon    = 0;
                purchRegisterReportTmp.LineAmount       = 0;
                purchRegisterReportTmp.update();
            }
        }

        while select forupdate purchRegisterReportTmp
            order by DeliveryOrderNum
            where purchRegisterReportTmp.DeliveryOrderNum
        {
            if (curPackingSlipId != purchRegisterReportTmp.DeliveryOrderNum)
            {
                curPackingSlipId    = purchRegisterReportTmp.DeliveryOrderNum;
            }
            else
            {
                purchRegisterReportTmp.DeliveryQty      = 0;
                purchRegisterReportTmp.update();
            }
        }
        ttscommit;
    }
}

