public void insertQualitySpecifications()
{
    ETG_VendPackingQualityGrp       vendPackingQualityGrp;

    while select maxof(InventTransIdGRN), maxof(DeliveryOrderNum), maxof(InvoiceId) from purchRegisterReportTmp
        group by PurchId, PurchLine
        where purchRegisterReportTmp.PurchId
        && purchRegisterReportTmp.PurchLine
        && purchRegisterReportTmp.VendPackingSlipTrans
    {
        ssrsReportMultiParametersTmp.ElementStr1    = purchRegisterReportTmp.PurchId;
        ssrsReportMultiParametersTmp.ElementRecId1  = purchRegisterReportTmp.PurchLine;
        ssrsReportMultiParametersTmp.ElementStr2    = purchRegisterReportTmp.InventTransIdGRN;
        ssrsReportMultiParametersTmp.ElementStr3    = purchRegisterReportTmp.DeliveryOrderNum;
        if (purchRegisterReportTmp.InvoiceId)
        {
            ssrsReportMultiParametersTmp.ElementStr4= purchRegisterReportTmp.InvoiceId;
        }
        ssrsReportMultiParametersTmp.insert();
        currentTransactionIdGRN                     = ssrsReportMultiParametersTmp.CreatedTransactionId;
    }

    while select ssrsReportMultiParametersTmp
        where ssrsReportMultiParametersTmp.CreatedTransactionId == currentTransactionIdGRN
    {
        while select vendPackingQualityGrp
            where vendPackingQualityGrp.InventTransId == ssrsReportMultiParametersTmp.ElementStr2
        {
            purchRegisterReportTmp.clear();
            purchRegisterReportTmp.GroupID                      = vendPackingQualityGrp.GroupID;
            purchRegisterReportTmp.GroupDescription             = vendPackingQualityGrp.GroupDescription;
            purchRegisterReportTmp.ResultValue                  = vendPackingQualityGrp.ResultValue;
            purchRegisterReportTmp.SubGroupID                   = vendPackingQualityGrp.SubGroupID;
            purchRegisterReportTmp.SubGroupDescription          = vendPackingQualityGrp.SubGroupDescription;
            purchRegisterReportTmp.ETG_VendPackingQualityGrp    = vendPackingQualityGrp.RecId;
            purchRegisterReportTmp.PurchId                      = ssrsReportMultiParametersTmp.ElementStr1;
            purchRegisterReportTmp.PurchLine                    = ssrsReportMultiParametersTmp.ElementRecId1;
            purchRegisterReportTmp.InventTransIdGRN             = ssrsReportMultiParametersTmp.ElementStr2;
            purchRegisterReportTmp.DeliveryOrderNum             = ssrsReportMultiParametersTmp.ElementStr3;
            if (ssrsReportMultiParametersTmp.ElementStr4)
            {
                purchRegisterReportTmp.InvoiceId                = ssrsReportMultiParametersTmp.ElementStr4;
            }
            purchRegisterReportTmp.insert();
        }
    }

    delete_from ssrsReportMultiParametersTmp
        where ssrsReportMultiParametersTmp.CreatedTransactionId == currentTransactionIdGRN;
}

/// <summary>
///    inserting charges codes of a Agreement for specified invoiceid
/// </summary>
public void insertChargeCodes()
{
    RecordInsertList            chargeCodesList;
    ETG_ActualAgreementNew      actualAgreementNew;
    ETG_Chargecodelines         chargecodelines;
    ETG_ChargeCodes             chargeCodes;

    if (!isDetailReport)
    {
        while select maxof(PurchId) from purchRegisterReportTmp
            group by PurchLine, PurchConractNumber, InvoiceId, DeliveryOrderNum
            where purchRegisterReportTmp.PurchLine
            && purchRegisterReportTmp.PurchConractNumber
            && purchRegisterReportTmp.InvoiceId
            && purchRegisterReportTmp.IsActualOrderLine == NoYes::Yes
        {
            ssrsReportMultiParametersTmp.clear();
            ssrsReportMultiParametersTmp.ElementRecId1  = purchRegisterReportTmp.PurchLine;
            ssrsReportMultiParametersTmp.ElementStr1    = purchRegisterReportTmp.PurchConractNumber;
            ssrsReportMultiParametersTmp.ElementStr2    = purchRegisterReportTmp.InvoiceId;
            ssrsReportMultiParametersTmp.ElementStr3    = purchRegisterReportTmp.PurchId;
            ssrsReportMultiParametersTmp.ElementStr4    = purchRegisterReportTmp.DeliveryOrderNum;
            ssrsReportMultiParametersTmp.insert();
            currentTransactionIdChrg                    = ssrsReportMultiParametersTmp.CreatedTransactionId;
        }
    }
    else
    {
        while select maxof(PurchId) from purchRegisterReportTmp
            group by ActualPurchLine, PurchConractNumber, InvoiceId, DeliveryOrderNum
            where purchRegisterReportTmp.ActualPurchLine
            && purchRegisterReportTmp.PurchConractNumber
            && purchRegisterReportTmp.InvoiceId
            && purchRegisterReportTmp.IsActualOrderLine == NoYes::No
        {
            ssrsReportMultiParametersTmp.clear();
            ssrsReportMultiParametersTmp.ElementRecId1  = purchRegisterReportTmp.ActualPurchLine;
            ssrsReportMultiParametersTmp.ElementStr1    = purchRegisterReportTmp.PurchConractNumber;
            ssrsReportMultiParametersTmp.ElementStr2    = purchRegisterReportTmp.InvoiceId;
            ssrsReportMultiParametersTmp.ElementStr3    = purchRegisterReportTmp.PurchId;
            ssrsReportMultiParametersTmp.ElementStr4    = purchRegisterReportTmp.DeliveryOrderNum;
            ssrsReportMultiParametersTmp.insert();
            currentTransactionIdChrg                    = ssrsReportMultiParametersTmp.CreatedTransactionId;
        }
    }

    while select ssrsReportMultiParametersTmp
        where ssrsReportMultiParametersTmp.CreatedTransactionId == currentTransactionIdChrg
    {
        while select chargecodelines
            where chargecodelines.InvoiceId == ssrsReportMultiParametersTmp.ElementStr2
        exists join chargeCodes
            where chargeCodes.ETG_Estimation == chargecodelines.ETG_Estimation
            && chargeCodes.PurchNumberSequence == chargecodelines.PurchNumberSequence
            && chargeCodes.PurchNumberSequence == ssrsReportMultiParametersTmp.ElementStr1
        {
            purchRegisterReportTmp.clear();
            purchRegisterReportTmp.PurchLine            = ssrsReportMultiParametersTmp.ElementRecId1;
            purchRegisterReportTmp.PurchConractNumber   = ssrsReportMultiParametersTmp.ElementStr1;
            purchRegisterReportTmp.InvoiceId            = ssrsReportMultiParametersTmp.ElementStr2;
            purchRegisterReportTmp.PurchId              = ssrsReportMultiParametersTmp.ElementStr3;
            purchRegisterReportTmp.DeliveryOrderNum     = ssrsReportMultiParametersTmp.ElementStr4;
            purchRegisterReportTmp.ChargeCode           = chargecodelines.MarkupCode;
            //purchRegisterReportTmp.EstimatedValue       = chargecodelines.Value;
            purchRegisterReportTmp.EstimatedValue       = chargecodelines.AmountMST;
            purchRegisterReportTmp.insert();
        }

        while select actualAgreementNew
            where actualAgreementNew.InvoiceId == ssrsReportMultiParametersTmp.ElementStr2
        join chargecodelines
            where chargecodelines.PurchId == actualAgreementNew.PurchId
            && chargecodelines.InvoiceId == ssrsReportMultiParametersTmp.ElementStr2
        exists join chargeCodes
            where chargeCodes.ETG_Estimation == chargecodelines.ETG_Estimation
            && chargeCodes.PurchNumberSequence == chargecodelines.PurchNumberSequence
            && actualAgreementNew.ETG_Estimation == chargeCodes.ETG_Estimation
            && actualAgreementNew.PurchNumberSequence == chargeCodes.PurchNumberSequence
            && chargeCodes.PurchNumberSequence == ssrsReportMultiParametersTmp.ElementStr1
        {
            purchRegisterReportTmp.clear();
            purchRegisterReportTmp.PurchLine            = ssrsReportMultiParametersTmp.ElementRecId1;
            purchRegisterReportTmp.PurchConractNumber   = ssrsReportMultiParametersTmp.ElementStr1;
            purchRegisterReportTmp.InvoiceId            = ssrsReportMultiParametersTmp.ElementStr2;
            purchRegisterReportTmp.PurchId              = ssrsReportMultiParametersTmp.ElementStr3;
            purchRegisterReportTmp.DeliveryOrderNum     = ssrsReportMultiParametersTmp.ElementStr4;
            purchRegisterReportTmp.ChargeCode           = chargecodelines.MarkupCode;
            //purchRegisterReportTmp.ActualValue          = actualAgreementNew.Value;
            purchRegisterReportTmp.ActualValue          = actualAgreementNew.AmountMST;
            purchRegisterReportTmp.insert();
        }
    }

    delete_from ssrsReportMultiParametersTmp
        where ssrsReportMultiParametersTmp.CreatedTransactionId == currentTransactionIdChrg;
}

public  boolean isGRNWithMulipleInvoices(PurchId   _PurchId, InventTransId _GRNInventTransId)
{
    boolean             mulipleInvoices = false;
    VendInvoiceJour     vendInvoiceJour;
    VendInvoiceTrans    vendInvoiceTrans;

    select count(RecId) from vendInvoiceJour
    exists join vendInvoiceTrans
        where vendInvoiceTrans.PurchId == vendInvoiceJour.PurchId
        && vendInvoiceTrans.InvoiceId == vendInvoiceJour.InvoiceId
        && vendInvoiceTrans.InvoiceDate == vendInvoiceJour.InvoiceDate
        && vendInvoiceTrans.numberSequenceGroup == vendInvoiceJour.numberSequenceGroup
        && vendInvoiceTrans.InternalInvoiceId == vendInvoiceJour.InternalInvoiceId
        && vendInvoiceTrans.PurchId == _PurchId
        && vendInvoiceTrans.InventTransId == _GRNInventTransId;

    mulipleInvoices = vendInvoiceJour.RecId > 1 ? true : false;

    return  mulipleInvoices;
}

public  boolean isGRNWithMulipleItems(PurchId   _PurchId, InventTransId _GRNInventTransId)
{
    boolean                 mulipleInvoices = false;
    VendPackingSlipJour     vendPackingSlipJourLoc;
    VendPackingSlipTrans    vendPackingSlipTransLoc;

    select count(RecId) from vendPackingSlipTransLoc
    exists join vendPackingSlipJourLoc
        where vendPackingSlipTransLoc.vendPackingslipJour == vendPackingSlipJourLoc.RecId
        && vendPackingSlipTransLoc.OrigPurchid == _PurchId
        && vendPackingSlipTransLoc.InventTransId == _GRNInventTransId;

    mulipleInvoices = vendPackingSlipTransLoc.RecId > 1 ? true : false;

    return  mulipleInvoices;
}
